INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b6e9caae-f11f-4586-a083-da99f15ce8a2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django URL Routing — urls.py Patterns, Parameters, and include()$escape$,
  $escape$Django's URL dispatcher maps request paths to views via `urlpatterns` lists in `urls.py`. Each entry is a `path()` or `re_path()` call. `path()` uses angle-bracket converters (`<int:pk>`, `<slug:slug>`, `<uuid:id>`) that both match and cast the value before it reaches your view. `re_path()` accepts raw regex for edge cases.

Grouping and prefixing routes is done with `include()`. You define app-level `urlpatterns` in each app's `urls.py`, then mount them under a prefix in the project-level `urls.py`. Django also supports `app_name` namespacing — set it in the app's `urls.py` and reference routes as `'blog:post-detail'` in `reverse()` or `{% url %}`, preventing name collisions across apps. Converters are extensible: register a custom one via `register_converter()` if the five built-ins (`str`, `int`, `slug`, `uuid`, `path`) don't cover your pattern.$escape$,
  $escape$# blog/urls.py
from django.urls import path
from . import views

app_name = 'blog'

urlpatterns = [
    path('', views.post_list, name='post-list'),
    path('<int:pk>/', views.post_detail, name='post-detail'),
    path('<slug:slug>/edit/', views.post_edit, name='post-edit'),
]

# project/urls.py
from django.urls import path, include

urlpatterns = [
    path('blog/', include('blog.urls')),
]

# Reverse: reverse('blog:post-detail', kwargs={'pk': 42})$escape$,
  $escape$python$escape$,
