INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a1843fc4-949f-4845-828e-523d6c855062',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django ORM — Killing N+1 Queries Before They Kill Your App$escape$,
  $escape$Django's ORM is a full ORM — it maps Python objects to SQL rows and manages relationships automatically. That power comes with a trap: the N+1 query problem. Accessing a related object inside a loop without prefetching fires one extra query per row. Fix it with `select_related` for ForeignKey/OneToOne (SQL JOIN) and `prefetch_related` for ManyToMany/reverse FK (separate IN query, Python-side join). Use `django-debug-toolbar` or log `django.db.backends` to spot N+1s in development. For complex filtering, Django's `Q` objects and `annotate()` with `F` expressions let you push logic into SQL rather than Python. Avoid raw `queryset.filter()` loops — compose querysets lazily and evaluate once. On the migration side, always review `makemigrations` output before applying; use `RunSQL` for custom indexes and `SeparateDatabaseAndState` when renaming models to avoid table rebuilds. Never run `migrate` without `--plan` in production.$escape$,
  $escape$from django.db.models import Prefetch

# Bad: N+1 — one query per post's author
posts = Post.objects.all()
for post in posts:
    print(post.author.username)  # hits DB each iteration

# Good: 1 JOIN query
posts = Post.objects.select_related('author').all()

# Good: prefetch tags (M2M) with a filtered queryset
posts = Post.objects.prefetch_related(
    Prefetch('tags', queryset=Tag.objects.filter(active=True))
).select_related('author')$escape$,
