INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5912098d-eb2e-495f-90e0-b31bd8bfd537',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django Middleware — Request Pipeline, Ordering, and Route-Specific Patterns$escape$,
  $escape$Django's middleware stack is a list of callables in `MIDDLEWARE` (settings.py) that wraps every request/response cycle. Order is critical: middleware processes requests top-down and responses bottom-up. `SecurityMiddleware` must sit first to enforce HTTPS redirects before anything else runs; `SessionMiddleware` must precede `AuthenticationMiddleware` since auth depends on the session.

Each middleware class implements `__init__(self, get_response)` and `__call__(self, request)`. Call `get_response(request)` to pass control down the chain. Hook into `process_view`, `process_exception`, or `process_template_response` for finer-grained interception.

Django has no native per-route middleware, but you can simulate it using a decorator-based approach with `django.utils.decorators.decorator_from_middleware`, or by conditionally short-circuiting inside `__call__` based on `request.path`. For async views, inherit from `django.utils.deprecation.MiddlewareMixin` or write a pure async middleware with `async def __call__`. Misordering — e.g., placing `GZipMiddleware` after `SecurityMiddleware` — silently breaks compression on HTTPS responses.$escape$,
  $escape$# settings.py — order matters
MIDDLEWARE = [
    'django.middleware.security.SecurityMiddleware',   # must be first
    'django.contrib.sessions.middleware.SessionMiddleware',
    'django.middleware.common.CommonMiddleware',
    'django.contrib.auth.middleware.AuthenticationMiddleware',  # needs session
    'myapp.middleware.RequestTimingMiddleware',
]

# myapp/middleware.py
import time

class RequestTimingMiddleware:
    def __init__(self, get_response):
        self.get_response = get_response

    def __call__(self, request):
        start = time.monotonic()
        response = self.get_response(request)
        duration = time.monotonic() - start
        response['X-Request-Duration'] = f'{duration:.4f}s'
        return response$escape$,
  $escape$python$escape$,
