INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '95be7f49-5c4a-48cd-a5e1-ca8f75285221',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django Input Validation — Schema Validation, Sanitization, and Error Responses at the Boundary$escape$,
  $escape$Django Forms and DRF Serializers are your validation boundary — never let raw request data reach your business logic. Use `serializers.Serializer` (or `ModelSerializer`) to declare schema upfront: field types, `required`, `allow_null`, `max_length`, and custom `validate_<field>` methods run automatically on `.is_valid()`. Call `.is_valid(raise_exception=True)` in DRF views to auto-return a 400 with structured error detail — no manual error shaping needed. For sanitization, DRF doesn't HTML-escape by default; if you're storing user content rendered in a browser, run it through `bleach.clean()` before saving. Avoid `request.data` directly in model constructors or raw SQL — always go through a validated serializer. For nested objects, use nested serializers with `many=True` or `allow_empty=False` rather than iterating raw lists. Custom cross-field validation belongs in `validate()` (the object-level method), not in the view. This keeps validation declarative, testable, and co-located with your schema.$escape$,
  $escape$from rest_framework import serializers

class CreateCommentSerializer(serializers.Serializer):
    post_id = serializers.UUIDField()
    body = serializers.CharField(min_length=1, max_length=1000)
    parent_id = serializers.UUIDField(required=False, allow_null=True)

    def validate_body(self, value):
        import bleach
        return bleach.clean(value.strip())

    def validate(self, data):
        if data.get('parent_id') == data['post_id']:
            raise serializers.ValidationError('parent_id cannot equal post_id')
        return data

# In your APIView:
# serializer = CreateCommentSerializer(data=request.data)
# serializer.is_valid(raise_exception=True)  # returns 400 on failure
# validated = serializer.validated_data$escape$,
  $escape$python$escape$,
