INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5bd9fb8b-27b5-44c6-861a-c5da876ad091',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django REST Framework — Serialization, camelCase, and Null Field Handling$escape$,
  $escape$DRF serializers are your request/response DTOs. Define them explicitly rather than relying on ModelSerializer auto-fields — it gives you full control over shape and validation. For camelCase output (required by most JS frontends), use `djangorestframework-camel-case`: wrap your renderer and parser in settings and field names automatically convert between snake_case internally and camelCase externally — zero manual mapping.

For null handling, DRF's `allow_null=True` permits null input, but pair it with `required=False` if the field is optional on writes. On reads, set `default=None` only when the field can be legitimately absent from the DB row. Avoid `SerializerMethodField` for simple transformations — use a custom field or override `to_representation()` on the serializer instead. For write-only fields (passwords, tokens), set `write_only=True`; for computed read-only fields, use `read_only=True`. Validate cross-field logic in `validate()`, not `validate_<field>()`, to access the full `data` dict.$escape$,
  $escape$# settings.py
REST_FRAMEWORK = {
    'DEFAULT_RENDERER_CLASSES': [
        'djangorestframework_camel_case.render.CamelCaseJSONRenderer',
    ],
    'DEFAULT_PARSER_CLASSES': [
        'djangorestframework_camel_case.parser.CamelCaseJSONParser',
    ],
}

# serializers.py
class UserProfileSerializer(serializers.Serializer):
    display_name = serializers.CharField()               # → displayName in JSON
    github_url = serializers.URLField(allow_null=True, required=False, default=None)
    api_token = serializers.CharField(write_only=True)
    post_count = serializers.IntegerField(read_only=True)

    def validate(self, data):
        if data.get('github_url') and 'github.com' not in data['github_url']:
            raise serializers.ValidationError({'github_url': 'Must be a GitHub URL.'})
        return data$escape$,
  $escape$python$escape$,
