INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a4abe217-f71d-4251-bdb8-d3601d883df2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django Settings — Env Vars, Split Configs, and Secrets Without Leaks$escape$,
  $escape$Django's single `settings.py` breaks down fast in real projects. The idiomatic fix: split into `settings/base.py`, `settings/local.py`, and `settings/production.py`, then point `DJANGO_SETTINGS_MODULE` at the right one per environment. For secrets, use `django-environ` or `python-decouple` to pull values from `.env` files or OS environment variables — never hardcode `SECRET_KEY` or database credentials. `django-environ` lets you cast types inline: `env('DEBUG', cast=bool, default=False)` and parse `DATABASE_URL` into Django's `DATABASES` dict with a single `env.db()` call. For production secrets on Azure or AWS, mount them as environment variables via your container runtime or use `django-storages` with Azure Key Vault. Always set `SECRET_KEY` via env, validate it's not the default in `AppConfig.ready()`, and add `.env` to `.gitignore`. Use `django-environ`'s `EnvError` to fail fast on missing required vars at startup rather than at runtime. Keep `ALLOWED_HOSTS`, `CORS_ALLOWED_ORIGINS`, and `DATABASES` out of version control entirely.$escape$,
  $escape$# settings/base.py
import environ

env = environ.Env(
    DEBUG=(bool, False),
)
environ.Env.read_env()  # reads .env in project root

SECRET_KEY = env('SECRET_KEY')  # raises EnvError if missing
DEBUG = env('DEBUG')
DATABASES = {'default': env.db('DATABASE_URL')}
ALLOWED_HOSTS = env.list('ALLOWED_HOSTS', default=[])

# settings/production.py
from .base import *

SECURE_SSL_REDIRECT = True
SESSION_COOKIE_SECURE = True$escape$,
  $escape$python$escape$,
