INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '110fab95-adda-40c5-9e19-0f97260e85dd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django Structured Logging — Correlation IDs and Request Middleware$escape$,
  $escape$Django's default logging uses Python's `logging` module, but plain-text logs break in distributed systems. Switch to structured JSON logs using `python-json-logger` and inject a correlation ID per request so you can trace a full lifecycle across services.

Create a middleware that reads `X-Request-ID` from headers (or generates a UUID fallback), stores it in `threading.local()`, and makes it available to a custom `logging.Filter`. That filter injects the correlation ID into every log record emitted during that request.

Configure `LOGGING` in `settings.py` to use `pythonjsonlogger.jsonlogger.JsonFormatter`. Every log call — including Django's built-in `django.request` logger — will emit structured JSON with `correlation_id`, `level`, `timestamp`, and your custom fields. Pair this with `structlog` if you need context accumulation (e.g., attaching `user_id` mid-request). In production, ship these JSON lines directly to CloudWatch, Datadog, or Loki without any parsing regex.$escape$,
  $escape$# middleware.py
import uuid, logging, threading
from django.utils.deprecation import MiddlewareMixin

_local = threading.local()

class CorrelationIdMiddleware(MiddlewareMixin):
    def process_request(self, request):
        _local.correlation_id = request.headers.get("X-Request-ID", str(uuid.uuid4()))
        request.correlation_id = _local.correlation_id

class CorrelationIdFilter(logging.Filter):
    def filter(self, record):
        record.correlation_id = getattr(_local, "correlation_id", "-")
        return True

# settings.py snippet
# Add filter to your handler and set formatter to JsonFormatter$escape$,
  $escape$python$escape$,
