INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fe813e51-972c-4ceb-a955-a3edf841a2e9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django Background Jobs — Celery, Beat, and Worker Process Patterns$escape$,
  $escape$Django has no built-in task queue, but Celery is the de facto standard. Define tasks with @shared_task (preferred over @app.task) so they're decoupled from the Celery app instance — critical for reusable Django apps. Tasks are dispatched via .delay() or .apply_async(), the latter giving control over eta, countdown, queue routing, and retry policy via autoretry_for and max_retries. Bind the task (bind=True) to access self.retry() for manual retry logic with exponential backoff.

For scheduled jobs, celery-beat reads a CELERY_BEAT_SCHEDULE dict in settings.py and enqueues tasks on a cron or interval. In production, store the schedule in the database using django-celery-beat so you can edit it at runtime without a redeploy.

Run workers with celery -A myproject worker -Q default,priority --concurrency=4. Use separate named queues (-Q) to isolate slow tasks (e.g. report generation) from fast ones (e.g. sending emails). Always set CELERY_TASK_ALWAYS_EAGER = True in tests to execute tasks synchronously without a broker.$escape$,
  $escape$# tasks.py
from celery import shared_task
from celery.utils.log import get_task_logger

logger = get_task_logger(__name__)

@shared_task(bind=True, autoretry_for=(Exception,), max_retries=3, default_retry_delay=60)
def send_welcome_email(self, user_id: int) -> None:
    from myapp.models import User
    user = User.objects.get(pk=user_id)
    logger.info("Sending welcome email to %s", user.email)
    # ... email logic

# settings.py
from celery.schedules import crontab

CELERY_BEAT_SCHEDULE = {
    "daily-digest": {
        "task": "myapp.tasks.send_daily_digest",
        "schedule": crontab(hour=8, minute=0),
    },
}$escape$,
  $escape$python$escape$,
