INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b1c55975-e6e2-48d1-972e-7fec9d9fec2b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django's Dev Tooling Stack — Hot Reload, Management Commands, and django-extensions$escape$,
  $escape$Django's built-in `runserver` auto-reloads on file save via `StatReloader` (default) or `WatchmanReloader` if pywatchman is installed — Watchman is significantly faster on large codebases. Enable it by installing `pywatchman` and ensuring `DJANGO_WATCHMAN_TIMEOUT` is set if needed.

For code generation and scaffolding, `startapp` is just the beginning. `django-extensions` adds `show_urls`, `shell_plus` (auto-imports all models), and critically `generate_secret_key`. For full scaffold generation, `djangorestframework` pairs with `django-rest-framework-stubs` for typed ViewSet generation.

The real power is custom management commands. Drop a file in `yourapp/management/commands/seed_db.py`, subclass `BaseCommand`, and wire it to `handle()` — you get argument parsing, `--verbosity`, and `--no-color` for free. Combine with `call_command()` in tests for isolated fixture seeding. For async-aware dev workflows, `DJANGO_ALLOW_ASYNC_UNSAFE=true` unblocks ORM calls in async shells without full ASGI setup.$escape$,
  $escape$# yourapp/management/commands/seed_db.py
from django.core.management.base import BaseCommand
from yourapp.models import Article

class Command(BaseCommand):
    help = 'Seed articles for local dev'

    def add_arguments(self, parser):
        parser.add_argument('--count', type=int, default=10)

    def handle(self, *args, **options):
        count = options['count']
        articles = [Article(title=f'Article {i}') for i in range(count)]
        Article.objects.bulk_create(articles)
        self.stdout.write(self.style.SUCCESS(f'Seeded {count} articles'))$escape$,
  $escape$python$escape$,
